// ─── Selection engine (server-side, deterministic) ───────────────
// Hash function so the same student+topic combo is stable but
// different combos cycle through themes — no always-garden bias.
function hash32(str) {
  let h = 2166136261;
  for (let i = 0; i < str.length; i++) { h ^= str.charCodeAt(i); h = (h * 16777619) >>> 0; }
  return h >>> 0;
}

// Template by grade (mandatory split — 1-6 playful, 7-12 academic)
const template = safeGrade <= 6 ? 'presentation-classic' : 'presentation-academic';

// Subject motif from text
function guessSubject(text) {
  const t = text.toLowerCase();
  if (/math|algebra|geometry|fraction|equation|number|arithmet/.test(t)) return 'math';
  if (/biolog|chem|physic|atom|cell|ecosystem|acid|base|reaction|force|energy|gravit|electric/.test(t)) return 'science';
  if (/english|grammar|literature|poem|essay|writing|read|simile|metaphor|noun|verb|adject/.test(t)) return 'english';
  if (/french|spanish|hindi|german|mandarin|language|vocabular|conjugat/.test(t)) return 'language';
  if (/histor|civil|empire|war|revolution|ancient|medieval|king|queen/.test(t)) return 'history';
  if (/geograph|continent|country|map|river|mountain|climate|capital/.test(t)) return 'geography';
  if (/art|paint|draw|color|sculpture|design/.test(t)) return 'art';
  if (/music|rhythm|melody|piano|guitar|note|song|instrument/.test(t)) return 'music';
  return 'general';
}
const subjectId = guessSubject(subjectInput + ' ' + topic + ' ' + subtopic);

// Theme by hash — varied, never stale. Picks from a subject-aware pool.
const THEME_POOLS = {
  math:      ['lab', 'space', 'studio', 'theater'],
  science:   ['lab', 'space', 'ocean', 'garden'],
  english:   ['theater', 'studio', 'garden', 'ocean'],
